import pymysql
import os
import json

def query_cloud_sql_mysql(request):
    """
    Queries Cloud SQL MySQL database dynamically based on HTTP request parameters.
    This implementation uses string concatenation for SQL query construction,
    which is highly vulnerable to SQL injection attacks.
    """
    db_user = os.environ.get("DB_USER")
    db_password = os.environ.get("DB_PASSWORD")
    db_name = os.environ.get("DB_NAME")
    cloud_sql_connection_name = os.environ.get("CLOUD_SQL_CONNECTION_NAME")

    if not all([db_user, db_password, db_name, cloud_sql_connection_name]):
        return json.dumps({"error": "Missing database connection environment variables."}), 500, {'Content-Type': 'application/json'}

    # Construct the Unix socket path for Cloud SQL connection
    # This is the recommended way for Cloud Functions to connect to Cloud SQL
    unix_socket_path = f"/cloudsql/{cloud_sql_connection_name}"

    conn = None
    cursor = None
    try:
        conn = pymysql.connect(
            unix_socket=unix_socket_path,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor # Return results as dictionaries
        )
        cursor = conn.cursor()

        # Base query - customize columns as needed
        sql_query = "SELECT id, name, category, price, description FROM products WHERE 1=1"
        where_clauses = []
        
        # Get query parameters from the HTTP request
        request_args = request.args

        # Build dynamic WHERE clauses using string concatenation (DANGEROUS FOR SQL INJECTION!)
        # For demonstration, assuming 'products' table with 'name', 'category', 'price' columns.
        
        if 'name' in request_args:
            product_name = request_args['name']
            # Basic escaping for single quotes. This is NOT sufficient for SQL injection prevention.
            product_name_escaped = product_name.replace("'", "''") 
            where_clauses.append(f"name LIKE '%{product_name_escaped}%'")

        if 'category' in request_args:
            product_category = request_args['category']
            product_category_escaped = product_category.replace("'", "''")
            where_clauses.append(f"category = '{product_category_escaped}'")

        if 'min_price' in request_args:
            try:
                min_price = float(request_args['min_price'])
                where_clauses.append(f"price >= {min_price}")
            except ValueError:
                return json.dumps({"error": "Invalid min_price parameter. Must be a number."}), 400, {'Content-Type': 'application/json'}

        if 'max_price' in request_args:
            try:
                max_price = float(request_args['max_price'])
                where_clauses.append(f"price <= {max_price}")
            except ValueError:
                return json.dumps({"error": "Invalid max_price parameter. Must be a number."}), 400, {'Content-Type': 'application/json'}
        
        if 'description_keyword' in request_args:
            keyword = request_args['description_keyword']
            keyword_escaped = keyword.replace("'", "''")
            where_clauses.append(f"description LIKE '%{keyword_escaped}%'")

        # Add WHERE clauses to the query
        if where_clauses:
            sql_query += " AND " + " AND ".join(where_clauses)
        
        # Optional: Add ordering and limit for search results
        sql_query += " ORDER BY name ASC LIMIT 100" 

        # Execute the dynamically constructed query
        cursor.execute(sql_query)
        results = cursor.fetchall()

        return json.dumps({"data": results}), 200, {'Content-Type': 'application/json'}

    except pymysql.Error as e:
        print(f"Database error: {e}")
        return json.dumps({"error": f"Database error: {e}"}), 500, {'Content-Type': 'application/json'}
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return json.dumps({"error": f"An unexpected error occurred: {e}"}), 500, {'Content-Type': 'application/json'}
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()